INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05050', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生命歷程觀點理論為跨領域所提出的人類行為的分析論述，對生命歷程觀點的概念敘述，下列何 者錯誤？', '["重視世代的概念，認為同一年齡層的人擁有相同的歷史文化背景，經歷相同的重大社會經濟變遷", "強調人的一生扮演並轉換不同角色，體驗不同的過渡期的角色功能與差異性", "認為人沒有自由意志和選擇的機會，生命的發展完全受限於當時的歷史脈絡或社會結構", "每個生命歷程階段都有其特殊的風險因子與保護因子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05051', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Selman提出角色取替理論中，依據不同觀點取替能力分為未分化（undifferentiated）、社會訊息 （social-information）、自我反應（self-reflective）、第三人（third-person）、社會群體（societal） 五個階段。其中與7～12歲的國小兒童發展有關的是那幾個階段？', '["未分化、社會訊息、社會群體", "未分化、第三人、社會群體", "未分化、社會訊息、社會群體", "社會訊息、自我反應、第三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05052', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成年人在進入職場後，可能會遭遇某些性別刻板、歧視與不友善的工作環境。其中「玻璃天花板 效應」（Glass Ceiling Effect）即是其一。請問對於玻璃天花板的敘述，下列何者錯誤？', '["是一種無形、人為的困難，以阻礙某些有資格的人在組織中升遷", "例如男女條件相當，升遷看似都有機會，但最後卻以女性需要多照顧家庭而讓男性升遷", "只有生理女性會遇到「玻璃天花板效應」", "玻璃天花板效應的產生常與職場環境不友善、薪資和升遷管道不平等等性別歧視有關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05053', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '知道自己罹患胃癌末期的阿美婆婆跟社工說：「我願意把我所有的財產捐給社福機構，你可以幫 我跟神明說，讓我多活幾年嗎？」如果就Kübler-Ross的哀傷五階段的主張，前述阿美婆婆言行 屬於那個階段？', '["否認", "憤怒", "接受", "討價還價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05054', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在青少年時期，有些父母常會使用負向語言來管教子女，而青少年也可能因父母等重要他人給予 的這些回應認同與內化，成為自我負面批判的歷程，甚至引發羞愧感。請問對於羞愧感所產生影 響的敘述，下列何者錯誤？', '["可以讓我們健康接納自己，並且有助於整合自我認定和自我內在的關係", "會以父母所對待的方式來羞辱自己，不斷自貶，甚至產生無價值感", "藉由憤怒將自己與他人隔離，好讓別人看不到自己的缺點或真實的樣子", "藉由追求權力來補償自己感覺的缺陷或隔絕羞愧感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05055', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「小夫社工在青少年機構服務，他邀請過去曾經接受機構服務、現在已經大學畢業的大雄來分享他當 時如何從挫敗中學習成長，找到自己的人生志向，期望藉由大雄的經歷可以鼓勵現在遇到挫折的青少 年。演講後，大雄果然成為現在機構中青少年的效仿對象。」請問前述例子呼應了那一個學習理論？', '["古典制約", "操作制約", "習得無助", "社會學習"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05056', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '皮亞傑（J. Piaget）認為人類與生俱來的認知過程中，以適應（adaptation）和________最為重要， 空格中應該填的是：', '["發展", "組織", "協調", "應用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05057', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '念小學二年級的小明看了某電視台八點檔播演的連續劇，劇中男主角掌摑女主角，並以極端鄙視的 語句羞辱她。小明之後在學校裡也對班上女同學如法炮製，試問，小明的行為是透過何種方式習得？', '["正增強", "消除", "懲罰", "觀察學習"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05058', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不在「人在環境中系統」（PIE）的分類裏？', '["社會角色問題", "整體功能評估問題", "心理違常問題", "環境問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05059', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '李文森（Levinson）的成人發展理論以「生活結構（life structure）」為概念，下列何者為其重要 發現？', '["人們會對自我感到好奇而努力將其能力發展到極限", "生活是一系列穩定與不穩定時期的交替，一輩子不斷地循環", "從嬰兒到成人都以相同的方式學習如何思考", "我們的行為乃是要不斷減少我們的期望及我們所擁有的，兩者之間的差異"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
